/*
 * ErgoGuard Chair - Web Dashboard
 * React Frontend
 */

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';
import PostureVisualizer from './components/PostureVisualizer';
import ScoreDashboard from './components/ScoreDashboard';
import AlertPanel from './components/AlertPanel';
import AnalyticsPanel from './components/AnalyticsPanel';

const API_BASE_URL = 'http://192.168.1.8:3000/api';
const WS_URL = 'ws://192.168.1.8:3000';

function App() {
  const [sensorData, setSensorData] = useState(null);
  const [analytics, setAnalytics] = useState(null);
  const [isConnected, setIsConnected] = useState(false);

  useEffect(() => {
    // Fetch latest data
    fetchLatestData();
    
    // Fetch analytics
    fetchAnalytics();
    
    // Set up WebSocket connection
    const ws = new WebSocket(WS_URL);
    
    ws.onopen = () => {
      console.log('WebSocket connected');
      setIsConnected(true);
    };
    
    ws.onmessage = (event) => {
      const message = JSON.parse(event.data);
      if (message.type === 'sensor_update') {
        setSensorData(message.data);
      }
    };
    
    ws.onerror = (error) => {
      console.error('WebSocket error:', error);
      setIsConnected(false);
    };
    
    ws.onclose = () => {
      console.log('WebSocket disconnected');
      setIsConnected(false);
    };
    
    // Poll for updates every 5 seconds (fallback)
    const interval = setInterval(() => {
      fetchLatestData();
      fetchAnalytics();
    }, 5000);
    
    return () => {
      ws.close();
      clearInterval(interval);
    };
  }, []);

  const fetchLatestData = async () => {
    try {
      const response = await axios.get(`${API_BASE_URL}/latest`);
      setSensorData(response.data);
    } catch (error) {
      console.error('Error fetching latest data:', error);
    }
  };

  const fetchAnalytics = async () => {
    try {
      const response = await axios.get(`${API_BASE_URL}/analytics?hours=24`);
      setAnalytics(response.data);
    } catch (error) {
      console.error('Error fetching analytics:', error);
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>ErgoGuard Chair Dashboard</h1>
        <div className="connection-status">
          <span className={isConnected ? 'connected' : 'disconnected'}>
            {isConnected ? '● Connected' : '○ Disconnected'}
          </span>
        </div>
      </header>

      <main className="dashboard">
        <div className="dashboard-grid">
          {/* Left Column */}
          <div className="left-column">
            <PostureVisualizer data={sensorData} />
            <AlertPanel data={sensorData} />
          </div>

          {/* Right Column */}
          <div className="right-column">
            <ScoreDashboard data={sensorData} analytics={analytics} />
            <AnalyticsPanel analytics={analytics} />
          </div>
        </div>
      </main>
    </div>
  );
}

export default App;
